#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, m, i, j, k = 0, found;

    scanf("%d %d", &n, &m);

    int arr1[n];
    for (i = 0; i < n; i++) {
        scanf("%d", &arr1[i]);
    }

    int arr2[m];
    for (i = 0; i < m; i++) {
        scanf("%d", &arr2[i]);
    }

    int unionArr[n + m];

    for (i = 0; i < n; i++) {
        unionArr[k++] = arr1[i];
    }

    for (i = 0; i < m; i++) {
        found = 0;
        for (j = 0; j < k; j++) {
            if (arr2[i] == unionArr[j]) {
                found = 1;
                break;
            }
        }
        if (found == 0) {
            unionArr[k++] = arr2[i];
        }
    }

    for (i = 0; i < k; i++) {
        for (j = i + 1; j < k; j++) {
            if (unionArr[i] > unionArr[j]) {
                int temp = unionArr[i];
                unionArr[i] = unionArr[j];
                unionArr[j] = temp;
            }
        }
    }

    for (i = 0; i < k; i++) {
        printf("%d", unionArr[i]);
        if (i < k - 1) {
            printf(" ");
        }
    }
    printf("\n");

    return 0;
}
